from collections import defaultdict, deque

class Solution(object):
    def buildMatrix(self, k, rowConditions, colConditions):
        """
        :type k: int
        :type rowConditions: List[List[int]]
        :type colConditions: List[List[int]]
        :rtype: List[List[int]]
        """
        def topological_sort(conditions):
            graph = defaultdict(list)
            indegree = {i: 0 for i in range(1, k + 1)}

            for u, v in conditions:
                graph[u].append(v)
                indegree[v] += 1

            queue = deque([i for i in range(1, k + 1) if indegree[i] == 0])
            order = []

            while queue:
                node = queue.popleft()
                order.append(node)

                for neighbor in graph[node]:
                    indegree[neighbor] -= 1
                    if indegree[neighbor] == 0:
                        queue.append(neighbor)

            # If we can't process all nodes, there's a cycle
            if len(order) != k:
                return None

            return order

        row_order = topological_sort(rowConditions)
        col_order = topological_sort(colConditions)

        if not row_order or not col_order:
            return []

        # Create position mappings
        row_pos = {num: i for i, num in enumerate(row_order)}
        col_pos = {num: j for j, num in enumerate(col_order)}

        # Build matrix
        matrix = [[0] * k for _ in range(k)]
        for num in range(1, k + 1):
            matrix[row_pos[num]][col_pos[num]] = num

        return matrix
